import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const discovery = await callMcpSkill({
    toolId,
    toolName: "find_moderate_probability_bets",
    args: {
      limit: 10,
      sortBy: "liquidity",
      category: "all",
      minPrice: 0.4,
      maxPrice: 0.6,
      minLiquidity: 1000000
    }
  });

  const opportunities = Array.isArray(discovery?.opportunities) ? discovery.opportunities : [];
  const shortlist = opportunities.slice(0, 5);

  const analyses = [];
  for (const opp of shortlist) {
    const query = opp?.market || opp?.slug || opp?.conditionId || "";
    const result = await callMcpSkill({
      toolId,
      toolName: "analyze_market_liquidity",
      args: query ? { marketQuery: query } : {}
    });
    analyses.push({ opportunity: opp, analysis: result });
  }

  const scoreTradability = (item) => {
    const a = item?.analysis || {};
    const spread = typeof a?.spread?.absolute === "number"
      ? a.spread.absolute
      : typeof a?.spread?.spreadCents === "number"
        ? a.spread.spreadCents / 100
        : typeof a?.spread?.spreadBps === "number"
          ? a.spread.spreadBps / 10000
          : null;

    const depth = typeof a?.depth?.totalDepthUsd === "number"
      ? a.depth.totalDepthUsd
      : typeof a?.depthWithin2Percent?.askDepthUsd === "number"
        ? a.depthWithin2Percent.askDepthUsd + (a.depthWithin2Percent.bidDepthUsd || 0)
        : null;

    const liquidityScore = a?.liquidityScore;
    const liquidityRank = {
      excellent: 5,
      good: 4,
      moderate: 3,
      poor: 2,
      illiquid: 1
    }[liquidityScore] || 0;

    const spreadPenalty = spread == null ? 1 : Math.min(3, spread * 20);
    const depthBonus = depth == null ? 0 : Math.min(3, depth / 500000);
    const whaleCost = a?.whaleCost?.sell5k;
    const whalePenalty = whaleCost && typeof whaleCost === "object" ? 0 : 0.5;

    return liquidityRank * 2 + depthBonus - spreadPenalty - whalePenalty;
  };

  const ranked = analyses
    .map((item) => ({
      market: item.opportunity?.market,
      url: item.opportunity?.url,
      currentPrice: item.opportunity?.currentPrice,
      liquidity: item.opportunity?.liquidity,
      volume24h: item.opportunity?.volume24h,
      conditionId: item.opportunity?.conditionId,
      currentAnalysis: item.analysis,
      tradabilityScore: scoreTradability(item)
    }))
    .sort((a, b) => b.tradabilityScore - a.tradabilityScore);

  return {
    fetchedAt: discovery?.fetchedAt,
    filters: {
      minPrice: 0.4,
      maxPrice: 0.6,
      minLiquidity: 1000000,
      category: "all"
    },
    summary: {
      matchingBets: Array.isArray(discovery?.opportunities) ? discovery.opportunities.length : 0,
      shortlistedForLiquidityCheck: shortlist.length
    },
    rankedMarkets: ranked.map((item, index) => ({
      rank: index + 1,
      market: item.market,
      url: item.url,
      currentPrice: item.currentPrice,
      liquidity: item.liquidity,
      volume24h: item.volume24h,
      conditionId: item.conditionId,
      tradabilityScore: item.tradabilityScore,
      liquidityScore: item.currentAnalysis?.liquidityScore,
      spread: item.currentAnalysis?.spread,
      depth: item.currentAnalysis?.depth,
      whaleCost: item.currentAnalysis?.whaleCost,
      recommendation: item.currentAnalysis?.recommendation
    })),
    rawDiscoverySample: opportunities.slice(0, 10)
  };
}

