import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const result = await callMcpSkill({
    toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
    toolName: "find_arbitrage_opportunities",
    args: {
      category: "politics",
      limit: 20
    }
  });

  const arbitrageOpportunities = Array.isArray(result?.arbitrageOpportunities)
    ? result.arbitrageOpportunities
    : [];
  const wideSpreadMarkets = Array.isArray(result?.wideSpreadMarkets)
    ? result.wideSpreadMarkets
    : [];

  const verifiedArb = arbitrageOpportunities.map((m) => ({
    market: m.market,
    url: m.url,
    conditionId: m.conditionId,
    buyYesAt: m.buyYesAt,
    buyNoAt: m.buyNoAt,
    totalCost: m.totalCost,
    potentialEdge: m.potentialEdge,
    edgePercent: m.edgePercent,
    liquidity: m.liquidity,
    note: m.note
  }));

  const passiveCandidates = wideSpreadMarkets
    .filter((m) => typeof m.spread === "number" && m.spread > 0)
    .map((m) => ({
      market: m.market,
      url: m.url,
      spread: m.spread,
      midPrice: m.midPrice,
      spreadPercent: m.spreadPercent
    }));

  const actionable = verifiedArb.length > 0
    ? verifiedArb
    : passiveCandidates.slice(0, 10);

  return {
    fetchedAt: result?.fetchedAt,
    scannedMarkets: result?.scannedMarkets,
    summary: result?.summary,
    methodology: result?.methodology,
    verifiedArbitrage: verifiedArb,
    wideSpreadMarkets: passiveCandidates,
    actionableTakeaway:
      verifiedArb.length > 0
        ? "The verified sub-$1 opportunities above are the best candidates for passive limit orders or near-riskless structures."
        : "No verified sub-$1 arbitrage was found in the scanned politics sample; the wide-spread names above are the best passive-order candidates, but they are not guaranteed arbitrage.",
    topActionable: actionable.slice(0, 10)
  };
}

