import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

const TOOL_ID = "294100e8-c648-4e5f-a254-95a14b56e398";

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function normalizeMarketCandidates(markets) {
  return asArray(markets)
    .filter((m) => m && typeof m === "object")
    .map((m) => ({
      title: m.title,
      slug: m.slug,
      url: m.url,
      conditionId: m.conditionId,
      liquidity: m.liquidity,
      volume24h: m.volume24h,
      currentPrice: m.currentPrice,
      category: m.category,
    }))
    .filter((m) => m.title && m.slug && m.url);
}

function isLikelyMultiOutcomePolitics(title) {
  if (!title || typeof title !== "string") return false;
  const t = title.toLowerCase();
  const hints = [
    "winner",
    "nominee",
    "election",
    "president",
    "governor",
    "senate",
    "house",
    "primary",
    "which candidate",
    "who will",
    "party",
  ];
  return hints.some((h) => t.includes(h));
}

export async function main() {
  const readBatch = await callMcpSkillsParallel({
    label: "polymarket-politics-liquidity-discovery",
    calls: [
      {
        key: "topMarkets",
        toolId: TOOL_ID,
        toolName: "get_top_markets",
        args: {
          category: "politics",
          sortBy: "liquidity",
          limit: 25,
        },
      },
      {
        key: "trending",
        toolId: TOOL_ID,
        toolName: "discover_trending_markets",
        args: {
          category: "politics",
          limit: 25,
          sortBy: "liquidity",
        },
      },
    ],
  });

  const topMarketsResult =
    readBatch.results.find((entry) => entry.key === "topMarkets" && entry.status === "fulfilled")?.value || null;
  const trendingResult =
    readBatch.results.find((entry) => entry.key === "trending" && entry.status === "fulfilled")?.value || null;

  const topMarkets = normalizeMarketCandidates(topMarketsResult?.markets);
  const trendingMarkets = normalizeMarketCandidates(trendingResult?.trendingMarkets);

  const mergedCandidates = [...topMarkets, ...trendingMarkets];
  const uniqueBySlug = new Map();
  for (const market of mergedCandidates) {
    if (!uniqueBySlug.has(market.slug)) uniqueBySlug.set(market.slug, market);
  }
  const dedupedCandidates = Array.from(uniqueBySlug.values());

  const multiOutcomeCandidates = dedupedCandidates.filter((m) => isLikelyMultiOutcomePolitics(m.title));
  const shortlisted = pickTopSemanticCandidates({
    target: "most liquid live multi-outcome politics event on Polymarket",
    candidates: multiOutcomeCandidates.length > 0 ? multiOutcomeCandidates : dedupedCandidates,
    requiredTerms: ["politics"],
    avoidTerms: ["single", "yes/no"],
    limit: 5,
  });

  const chosenEvent = shortlisted[0] || null;

  if (!chosenEvent || !chosenEvent.slug) {
    return {
      missingData: true,
      attemptedBranches: [
        "callMcpSkillsParallel(get_top_markets + discover_trending_markets, category=politics)",
        "pickTopSemanticCandidates(target='most liquid live multi-outcome politics event on Polymarket')",
      ],
      stopReason: "No suitable live multi-outcome politics event could be selected deterministically.",
      topMarketsReturned: topMarkets.length,
      trendingMarketsReturned: trendingMarkets.length,
      candidateCount: dedupedCandidates.length,
    };
  }

  const eventOutcomes = await callMcpSkill({
    toolId: TOOL_ID,
    toolName: "search_and_get_outcomes",
    args: {
      query: chosenEvent.title,
      category: "politics",
    },
