      },
      {
        key: "topPolitics",
        toolId,
        toolName: "get_top_markets",
        args: { category: "politics", limit: 20, sortBy: "volume" }
      }
    ]
  });

  const trendingResult =
    readBatch.results.find((entry) => entry.key === "trendingPolitics")?.status === "fulfilled"
      ? readBatch.results.find((entry) => entry.key === "trendingPolitics").value
      : null;

  const topMarketsResult =
    readBatch.results.find((entry) => entry.key === "topPolitics")?.status === "fulfilled"
      ? readBatch.results.find((entry) => entry.key === "topPolitics").value
      : null;

  const trendingMarkets = Array.isArray(trendingResult?.trendingMarkets) ? trendingResult.trendingMarkets : [];
  const topMarkets = Array.isArray(topMarketsResult?.markets) ? topMarketsResult.markets : [];

  const candidatePool = [...trendingMarkets, ...topMarkets].filter(Boolean);

  const ranked = pickTopSemanticCandidates({
    target: "the hottest live geopolitics market on Polymarket",
    candidates: candidatePool,
    requiredTerms: ["live"],
    avoidTerms: ["primary", "election", "nominee", "mvp", "district", "local", "proposal"],
    limit: 5
  });

  const shortlist = Array.isArray(ranked) ? ranked : [];
  const selected = shortlist[0] || null;

  const selectedSlug = selected?.slug;
  const selectedConditionId = selected?.conditionId;

  if (!selectedSlug && !selectedConditionId) {
    return {
      missingData: ["No clearly matched live geopolitics market from discovery batch"],
      attemptedBranches: [
        "discover_trending_markets(category=politics)",
        "get_top_markets(category=politics)",
        "pickTopSemanticCandidates(target=geopolitics)"
      ],
      stopReason: "no_confident_candidate"
    };
  }

  const activity = await callMcpSkill({
    toolId,
    toolName: "summarize_live_market_activity",
    args: selectedSlug
      ? { slug: selectedSlug, tradeLimit: 25, sortBy: "volume", endingWithinDays: 7 }
      : { conditionId: selectedConditionId, tradeLimit: 25, sortBy: "volume", endingWithinDays: 7 }
  });

  const tradesSummary = activity?.tradesSummary || null;
  const openInterest = activity?.openInterest || null;
  const recentTrades = Array.isArray(activity?.recentTrades) ? activity.recentTrades : [];

  const buyVolume = typeof tradesSummary?.buyVolume === "number" ? tradesSummary.buyVolume : null;
  const sellVolume = typeof tradesSummary?.sellVolume === "number" ? tradesSummary.sellVolume : null;

  let tapeRead = "Recent tape was unavailable or too thin to infer a short-term bias.";
  let shortTermImplication = "Wait for confirmation; the tape did not produce a clean directional edge.";

  if (typeof buyVolume === "number" && typeof sellVolume === "number") {
    const netFlow = buyVolume - sellVolume;
    if (netFlow > 0) {
      tapeRead = "Recent tape shows net buying pressure.";
      shortTermImplication = "Short-term positioning leans with the bid: momentum-following or dip-buying is more consistent than fading strength.";
    } else if (netFlow < 0) {
      tapeRead = "Recent tape shows net selling pressure.";
      shortTermImplication = "Short-term positioning leans defensive: rallies may be getting sold, so patience or fade setups look cleaner.";
    } else {
      tapeRead = "Recent tape looks balanced.";
      shortTermImplication = "Short-term positioning looks neutral; wait for a breakout or a better entry level.";
    }
  }

  return {
    discoverySummary: {
      candidatePoolSize: candidatePool.length,
      shortlistSize: shortlist.length,
      selectedMarket: selected
        ? {
            title: selected.title || selected.market || null,
            slug: selected.slug || null,
            conditionId: selected.conditionId || null,
            url: selected.url || null,
            currentPrice: selected.currentPrice ?? null,
            volume24h: selected.volume24h ?? selected.volume ?? null,
            liquidity: selected.liquidity ?? null,
            signal: selected.signal || null,
            whyTrending: selected.whyTrending || null
          }
        : null
    },
    recentActivity: {
      tradesSummary,
      openInterest,
      recentTradesSample: recentTrades.slice(0, 10)
    },
    positioningRead: {
      tapeRead,
      shortTermImplication
    },
    parallelTelemetry: readBatch.summary
  };
}

