import { callMcpSkill } from "@/lib/ai/skills/mcp";

const POLYMARKET_TOOL_ID = "294100e8-c648-4e5f-a254-95a14b56e398";

function safeArray(v) {
  return Array.isArray(v) ? v : [];
}

function toNumber(v) {
  return typeof v === "number" && Number.isFinite(v) ? v : null;
}

export async function main() {
  const probe = await callMcpSkill({
    toolId: POLYMARKET_TOOL_ID,
    toolName: "analyze_event_outcome_liquidity",
    args: {
      query: "Analyze live Polymarket liquidity for Iran escalation risk and identify any direct contracts tied to Iran escalation.",
      category: "politics",
      sortBy: "volume",
      limit: 8
    }
  });

  const eventTitle = probe && typeof probe.eventTitle === "string" ? probe.eventTitle : null;
  const analyzedOutcomes = safeArray(probe && probe.analyzedOutcomes);
  const needsOutcomeDisambiguation = !!(probe && probe.needsOutcomeDisambiguation);

  const directMatches = analyzedOutcomes.filter((o) => {
    const name = String(o && (o.matchedName || o.name || o.outcome || "")).toLowerCase();
    return name.includes("iran");
  });

  if (!eventTitle || analyzedOutcomes.length === 0 || directMatches.length === 0) {
    return {
      needsDifferentTools: true,
      stopReason:
        "The authorized Polymarket toolset did not return a directly grounded Iran-escalation market from the available probe path.",
      attemptedBranches: [
        "probe: analyze_event_outcome_liquidity(query='Iran escalation risk')",
        "parse: eventTitle/analyzedOutcomes/needsOutcomeDisambiguation"
      ],
      missingData: {
        eventTitle: eventTitle || null,
        analyzedOutcomesCount: analyzedOutcomes.length,
        directMatchesCount: directMatches.length,
        needsOutcomeDisambiguation
      }
    };
  }

  const ranked = directMatches
    .map((o) => ({
      matchedName: o.matchedName || o.name || o.outcome || null,
      tokenId: o.tokenId || null,
      conditionId: o.conditionId || null,
      liquidityScore: toNumber(o.liquidityScore),
      slippage5kPercent: toNumber(o.slippage5kPercent),
      bestAsk: toNumber(o.bestAsk),
      bestBid: toNumber(o.bestBid),
      volume: toNumber(o.volume)
    }))
    .sort((a, b) => {
      const aScore = a.liquidityScore == null ? -Infinity : a.liquidityScore;
      const bScore = b.liquidityScore == null ? -Infinity : b.liquidityScore;
      return bScore - aScore;
    });

  return {
    eventTitle,
    selectionMode: probe.selectionMode || null,
    selectionReason: probe.selectionReason || null,
    summary: probe.summary || null,
    needsOutcomeDisambiguation,
    analyzedOutcomes: ranked,
    selectedOutcome: ranked[0] || null,
    raw: {
      fetchedAt: probe.fetchedAt || null,
      eventSlug: probe.eventSlug || null,
      eventUrl: probe.eventUrl || null
    }
  };
}

