import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const result = await callMcpSkill({
    toolId,
    toolName: "find_moderate_probability_bets",
    args: {
      category: "all",
      minPrice: 0.7,
      maxPrice: 0.9,
      minLiquidity: 5000,
      sortBy: "liquidity",
      limit: 50
    }
  });

  const allOpportunities = Array.isArray(result?.opportunities) ? result.opportunities : [];
  const politicsTerms = [
    "election",
    "vote",
    "senate",
    "house",
    "congress",
    "trump",
    "biden",
    "iran",
    "israel",
    "ukraine",
    "war",
    "ceasefire",
    "president",
    "politic",
    "geopolitic",
    "cabinet",
    "parliament"
  ];

  const opportunities = allOpportunities.filter((m) => {
    const text = `${m.market || ""} ${m.slug || ""} ${m.whyThisBet || ""}`.toLowerCase();
    return politicsTerms.some((t) => text.includes(t));
  });

  const enriched = [];
  for (const m of opportunities) {
    const efficiency = m.conditionId
      ? await callMcpSkill({
          toolId,
          toolName: "check_market_efficiency",
          args: { conditionId: m.conditionId }
        })
      : null;

    const outcomes = Array.isArray(efficiency?.outcomes) ? efficiency.outcomes : [];
    const vig = typeof efficiency?.marketEfficiency?.vig === "number" ? efficiency.marketEfficiency.vig : null;
    const spreadBps =
      typeof efficiency?.marketEfficiency?.avgSpreadBps === "number"
        ? efficiency.marketEfficiency.avgSpreadBps
        : typeof efficiency?.marketEfficiency?.spreadBps === "number"
          ? efficiency.marketEfficiency.spreadBps
          : null;
    const price = typeof m.currentPrice === "number" ? m.currentPrice : null;
    const liquidity = typeof m.liquidity === "number" ? m.liquidity : null;
    const volume24h = typeof m.volume24h === "number" ? m.volume24h : null;

    const liquidityScore = liquidity === null ? 0 : Math.min(liquidity / 1000000, 5);
    const volumeScore = volume24h === null ? 0 : Math.min(volume24h / 250000, 3);
    const spreadPenalty = spreadBps === null ? 0 : Math.min(spreadBps / 100, 3);
    const vigPenalty = vig === null ? 0 : Math.min(vig * 10, 3);
    const thesisFit = price === null ? 0 : 1 - Math.abs(price - 0.8) / 0.3;
    const cleanliness = liquidityScore * 0.45 + volumeScore * 0.25 + Math.max(thesisFit, 0) * 0.3 - spreadPenalty * 0.15 - vigPenalty * 0.1;

    enriched.push({
      market: m.market,
      url: m.url,
      slug: m.slug,
      conditionId: m.conditionId,
      currentPrice: m.currentPrice,
      liquidity: m.liquidity,
      volume24h: m.volume24h,
      impliedProbability: m.impliedProbability,
      potentialReturn: m.potentialReturn,
      whyThisBet: m.whyThisBet,
      marketEfficiency: efficiency?.marketEfficiency,
      outcomeCount: outcomes.length,
      cleanlinessScore: Number(cleanliness.toFixed(3)),
      cleanlinessRank: null,
      thesisFit: thesisFit >= 0.5 ? "good thesis expression" : thesisFit >= 0.2 ? "acceptable thesis expression" : "weak thesis expression"
    });
  }

  enriched.sort((a, b) => b.cleanlinessScore - a.cleanlinessScore);
  enriched.forEach((m, i) => {
    m.cleanlinessRank = i === 0 ? "cleanest" : i === 1 ? "clean" : i === 2 ? "less clean" : "screened out";
  });

  return {
    summary: result?.summary,
    fetchedAt: result?.fetchedAt,
    rankingMethod: "probe-first politics/geopolitics filter over all categories, then rank by liquidity/volume, market efficiency, and thesis fit (lower-volatility = cleaner)",
    count: enriched.length,
    opportunities: enriched.slice(0, 3),
    note: "Returned the top 3 true politics/geopolitics markets and ranked them by cleanliness plus thesis expression."
  };
}

